@import 'tailwindcss';

/* Inter (SIL OFL) is the sans face, self-hosted as the v4.1 variable font — it
   ships with the system (open license). Berkeley Mono is a licensed typeface
   bundled here for local dev / the gallery; consumers supply their own mono. */
@font-face {
	font-family: 'Inter';
	src: url('/InterVariable.woff2') format('woff2');
	font-weight: 100 900;
	font-style: normal;
	font-display: swap;
}
@font-face {
	font-family: 'Berkeley Mono Variable';
	src: url('/Berkeley Mono Variable.woff2') format('woff2-variations');
	font-weight: 400 700;
	font-style: normal;
	font-display: swap;
}

@custom-variant dark (&:where(.dark, .dark *));

:root {
	--background: oklch(1 0 0);
	--foreground: oklch(0.27 0 0);
	--panel: oklch(0.96 0 0);
	--panel-foreground: oklch(0.27 0 0);
	--card: oklch(1 0 0);
	--card-foreground: oklch(0.27 0 0);
	--popover: oklch(1 0 0);
	--popover-foreground: oklch(0.27 0 0);
	--muted: oklch(0.97 0 0);
	--muted-foreground: oklch(0.44 0 0);
	--subtle-foreground: oklch(0.56 0 0);
	--border: oklch(0.87 0 0);
	--border-strong: oklch(0.71 0 0);
	--input: oklch(0.87 0 0);
	--ring: oklch(0.62 0.19 255);
	--primary: oklch(0.50 0.24 303);
	--primary-foreground: oklch(0.99 0 0);
	--secondary: oklch(0.96 0 0);
	--secondary-foreground: oklch(0.27 0 0);
	--accent: oklch(0.96 0 0);
	--accent-foreground: oklch(0.27 0 0);
	--destructive: oklch(0.58 0.22 27);
	--destructive-foreground: oklch(0.99 0 0);
	--success: oklch(0.60 0.17 150);
	--warning: oklch(0.80 0.16 85);
	--warning-strong: oklch(0.52 0.13 85);
	--destructive-strong: oklch(0.52 0.2 27);
	--highlight: oklch(0.85 0.15 90);
	--chart-1: oklch(0.646 0.222 41.116);
	--chart-2: oklch(0.6 0.118 184.704);
	--chart-3: oklch(0.398 0.07 227.392);
	--chart-4: oklch(0.828 0.189 84.429);
	--chart-5: oklch(0.769 0.188 70.08);
	--radius: 0rem;
	interpolate-size: allow-keywords;
}

.dark {
	/* Surface ladder spread for clearer layering: canvas -> card -> muted -> panel */
	--background: oklch(0.15 0 0);
	--foreground: oklch(0.96 0 0);
	--panel: oklch(0.255 0 0);
	--panel-foreground: oklch(0.96 0 0);
	--card: oklch(0.2 0 0);
	--card-foreground: oklch(0.96 0 0);
	--popover: oklch(0.205 0 0);
	--popover-foreground: oklch(0.96 0 0);
	--muted: oklch(0.235 0 0);
	--muted-foreground: oklch(0.72 0 0);
	--subtle-foreground: oklch(0.6 0 0);
	--border: oklch(0.34 0 0);
	--border-strong: oklch(0.48 0 0);
	--input: oklch(0.34 0 0);
	--ring: oklch(0.7 0.16 250);
	--primary: oklch(0.64 0.22 303);
	--primary-foreground: oklch(0.99 0 0);
	--secondary: oklch(0.25 0 0);
	--secondary-foreground: oklch(0.96 0 0);
	--accent: oklch(0.25 0 0);
	--accent-foreground: oklch(0.96 0 0);
	--destructive: oklch(0.62 0.2 25);
	--destructive-foreground: oklch(0.99 0 0);
	--success: oklch(0.7 0.16 150);
	--warning: oklch(0.8 0.15 85);
	--warning-strong: oklch(0.84 0.15 85);
	--destructive-strong: oklch(0.72 0.19 25);
	--highlight: oklch(0.78 0.14 90);
	--chart-1: oklch(0.7 0.2 41.116);
	--chart-2: oklch(0.7 0.13 184.704);
	--chart-3: oklch(0.62 0.15 227.392);
	--chart-4: oklch(0.83 0.19 84.429);
	--chart-5: oklch(0.77 0.19 70.08);
}

@theme inline {
	--color-background: var(--background);
	--color-foreground: var(--foreground);
	--color-panel: var(--panel);
	--color-panel-foreground: var(--panel-foreground);
	--color-card: var(--card);
	--color-card-foreground: var(--card-foreground);
	--color-popover: var(--popover);
	--color-popover-foreground: var(--popover-foreground);
	--color-muted: var(--muted);
	--color-muted-foreground: var(--muted-foreground);
	--color-subtle-foreground: var(--subtle-foreground);
	--color-border: var(--border);
	--color-border-strong: var(--border-strong);
	--color-input: var(--input);
	--color-ring: var(--ring);
	--color-primary: var(--primary);
	--color-primary-foreground: var(--primary-foreground);
	--color-secondary: var(--secondary);
	--color-secondary-foreground: var(--secondary-foreground);
	--color-accent: var(--accent);
	--color-accent-foreground: var(--accent-foreground);
	--color-destructive: var(--destructive);
	--color-destructive-foreground: var(--destructive-foreground);
	--color-success: var(--success);
	--color-warning: var(--warning);
	--color-warning-strong: var(--warning-strong);
	--color-destructive-strong: var(--destructive-strong);
	--color-highlight: var(--highlight);
	--color-chart-1: var(--chart-1);
	--color-chart-2: var(--chart-2);
	--color-chart-3: var(--chart-3);
	--color-chart-4: var(--chart-4);
	--color-chart-5: var(--chart-5);
	--radius: var(--radius);

	--font-mono: 'Berkeley Mono Variable', ui-monospace, 'SF Mono', Menlo, monospace;
	--font-sans: 'Inter', ui-sans-serif, system-ui, sans-serif;

	--spacing: 0.2rem;

	--text-2xs: 0.625rem;
	--text-2xs--line-height: calc(1 / 0.625);
	--text-xs: 0.6875rem;
	--text-xs--line-height: calc(1 / 0.6875);
	--text-sm: 0.75rem;
	--text-sm--line-height: calc(1 / 0.75);
	--text-base: 0.8125rem;
	--text-base--line-height: calc(1.125 / 0.8125);
	--text-lg: 0.875rem;
	--text-lg--line-height: calc(1.25 / 0.875);
	--text-xl: 1rem;
	--text-xl--line-height: calc(1.5 / 1);
	--text-2xl: 1.125rem;
	--text-2xl--line-height: calc(1.75 / 1.125);
	--text-3xl: 1.25rem;
	--text-3xl--line-height: calc(1.75 / 1.25);
	--text-4xl: 1.5rem;
	--text-4xl--line-height: calc(2 / 1.5);
	--text-5xl: 1.875rem;
	--text-5xl--line-height: calc(2.25 / 1.875);
	--text-6xl: 2.25rem;
	--text-6xl--line-height: calc(2.5 / 2.25);
	--text-7xl: 3rem;
	--text-7xl--line-height: 1;
	--text-8xl: 3.75rem;
	--text-8xl--line-height: 1;
	--text-9xl: 4.5rem;
	--text-controls-numeric: 0.78125rem;
	--text-controls-numeric--line-height: calc(1 / 0.78125);
}

@media (pointer: coarse) {
	:root {
		--spacing: 0.25rem;
	}

	html {
		font-size: 18px;
	}
}

html {
	font-size: 16px;
	overflow: clip;
	overscroll-behavior: none;
}

html,
body {
	width: 100%;
	height: 100%;
}

body {
	margin: 0;
	/* The app shell owns scrolling; the document itself never scrolls (kills rubber-band / stuck states). */
	overflow: clip;
	overscroll-behavior: none;
	@apply bg-background text-foreground font-sans text-base;
}

/* Layered so Tailwind's font-* utilities (in @layer utilities) can override it.
   Unlayered, this reset would beat every font-mono on a form control. */
@layer base {
	button,
	input,
	select,
	textarea {
		font: inherit;
	}
}

/* Semantic type roles — the only sanctioned way to set typography.
   Never pick a raw size by hand in UI; use a role.
   Distinct sizes: 10 / 11 / 12.5 / 13 / 16 / 18.
   To retune the system, edit a role here and every usage updates. */
@utility type-display {
	@apply font-sans text-2xl font-medium;
	line-height: 1.15;
	letter-spacing: -0.01em;
}
@utility type-heading {
	@apply font-sans text-xl font-medium;
	line-height: 1.2;
	letter-spacing: -0.01em;
}
@utility type-title {
	@apply font-sans text-base font-medium;
	line-height: 1.3;
}
@utility type-body {
	@apply font-sans text-base font-normal;
	line-height: 1.45;
}
@utility type-caption {
	@apply font-sans text-xs font-normal;
	line-height: 1.4;
}
@utility type-field {
	@apply font-sans text-sm font-medium;
	line-height: 1.25;
}
@utility type-label {
	@apply font-mono text-2xs font-medium uppercase;
	line-height: 1;
	letter-spacing: 0.06em;
}
@utility type-button {
	@apply font-mono text-xs font-medium uppercase;
	line-height: 1;
	letter-spacing: 0.04em;
}
@utility type-value {
	@apply font-mono text-controls-numeric font-medium tabular-nums;
	line-height: 1;
}
@utility type-code {
	@apply font-mono text-base font-normal;
	line-height: 1.55;
}

/* Spacing policy — spacing is owned by CONTAINERS, not components.
   Components ship margin-free; a parent stacks its children with one of these.
   All gaps are multiples of the 0.2rem base grid. Retune here, everywhere updates. */
@utility stack-tight {
	@apply flex flex-col gap-1; /* 0.2rem — parts of one control */
}
@utility stack-field {
	@apply flex flex-col gap-1.5; /* 0.3rem — elements inside a panel body */
}
@utility stack-group {
	@apply flex flex-col gap-2; /* 0.4rem — panels within a section */
}
@utility stack-section {
	@apply flex flex-col gap-4; /* 0.8rem — sections */
}
